1	export type Cell = [number, number];
2	
3	const isNeighbor = (a: Cell, b: Cell): boolean => {
4	  const dx = Math.abs(a[0] - b[0]);
5	  const dy = Math.abs(a[1] - b[1]);
6	  return (dx !== 0 || dy !== 0) && dx <= 1 && dy <= 1;
7	};
8	
9	const countLiveNeighbors = (cell: Cell, cells: Cell[]): number =>
10	  cells.filter((other) => isNeighbor(cell, other)).length;
11	
12	const survives = (liveNeighbors: number): boolean =>
13	  liveNeighbors === 2 || liveNeighbors === 3;
14	
15	const key = (cell: Cell): string => `${cell[0]},${cell[1]}`;
16	
17	const deadNeighborCandidates = (cells: Cell[]): Cell[] => {
18	  const live = new Set(cells.map(key));
19	  const seen = new Set<string>();
20	  const candidates: Cell[] = [];
21	  for (const [x, y] of cells) {
22	    for (let dx = -1; dx <= 1; dx++) {
23	      for (let dy = -1; dy <= 1; dy++) {
24	        if (dx === 0 && dy === 0) continue;
25	        const candidate: Cell = [x + dx, y + dy];
26	        const k = key(candidate);
27	        if (!live.has(k) && !seen.has(k)) {
28	          seen.add(k);
29	          candidates.push(candidate);
30	        }
31	      }
32	    }
33	  }
34	  return candidates;
35	};
36	
37	export const nextGeneration = (cells: Cell[]): Cell[] => {
38	  const survivors = cells.filter((cell) =>
39	    survives(countLiveNeighbors(cell, cells)),
40	  );
41	  const born = deadNeighborCandidates(cells).filter(
42	    (cell) => countLiveNeighbors(cell, cells) === 3,
43	  );
44	  return [...survivors, ...born];
45	};
